B.LD=new A.bd(B.c1,[B.IJ,B.JI,B.IA,'\ud83d\udd04 To send money via GIMTEL to another app:\n\n1\ufe0f\u20e3 On the Home screen tap the "G" GIMTEL icon\n2\ufe0f\u20e3 Enter the name of the target app\n   (Bankily, Click, Sedad, Masrivi, Moov Money, Bamis...)\n3\ufe0f\u20e3 Enter the recipient\'s phone number\n4\ufe0f\u20e3 Enter the amount to send\n5\ufe0f\u20e3 Enter your secret PIN to confirm\n\n\u2705 Money transferred to the other app instantly!','\ud83d\udd04 \u0644\u0625\u0631\u0633\u0627\u0644 \u0627\u0644\u0645\u0627\u0644 \u0639\u0628\u0631 \u062e\u062f\u0645\u0629 GIMTEL \u0644\u062a\u0637\u0628\u064a\u0642 \u0622\u062e\u0631:\n\n1\ufe0f\u20e3 \u0641\u064a \u0627\u0644\u0635\u0641\u062d\u0629 \u0627\u0644\u0631\u0626\u064a\u0633\u064a\u0629 \u0627\u0636\u063a\u0637 \u0639\u0644\u0649 \u0623\u064a\u0642\u0648\u0646\u0629 "G" \u062c\u064a\u0645\u062a\u0644\n2\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0627\u0633\u0645 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0645\u0633\u062a\u0644\u0645:\n   (\u0628\u0646\u0643\u064a\u0644\u064a\u060c \u0643\u0644\u064a\u0643\u060c \u0633\u064a\u062f\u0627\u062f\u060c \u0645\u0635\u0631\u0641\u064a\u060c \u0645\u0648\u0641 \u0645\u0648\u0646\u064a\u060c \u0628\u0627\u0645\u064a\u0633...)\n3\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645 \u0647\u0627\u062a\u0641 \u0627\u0644\u0645\u0633\u062a\u0644\u0645\n4\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0627\u0644\u0645\u0628\u0644\u063a \u0627\u0644\u0645\u0631\u0627\u062f \u0625\u0631\u0633\u0627\u0644\u0647\n5\ufe0f\u20e3 \u0623\u062f\u062e\u0644 \u0631\u0642\u0645\u0643 \u0627\u0644\u0633\u0631\u064a \u0644\u0644\u062a\u0623\u0643\u064a\u062f\n\n\u2705 \u064a\u062a\u0645 \u062a\u062d\u0648\u064a\u0644 \u0627\u0644\u0645\u0627\u0644 \u0644\u0644\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0622\u062e\u0631 \u0641\u0648\u0631\u0627\u064b!',"\ud83d\udd04 Pour envoyer via GIMTEL vers une autre app:\n\n1\ufe0f\u20e3 Sur l'accueil appuyez l'ic\xf4ne \"G\" GIMTEL\n2\ufe0f\u20e3 Entrez le nom de l'application destinataire:\n   (Bankily, Click, Sedad, Masrivi, Moov Money, Bamis...)\n3\ufe0f\u20e3 Entrez le num\xe9ro de t\xe9l\xe9phone du destinataire\n4\ufe0f\u20e3 Entrez le montant \xe0 envoyer\n5\ufe0f\u20e3 Entrez votre code PIN pour confirmer\n\n\u2705 Argent transf\xe9r\xe9 vers l'autre app instantan\xe9ment!"],t.EU)
